mapper.select:
SELECT r.review_number, r.review_title, r.review_content, r.review_rating, r.review_image, r.image_url, r.created_date, r.modified_date, u.user_name, u.user_number FROM review r JOIN users u ON r.user_number = u.user_number
AND (r.review_title LIKE CONCAT('%', #{keyword}, '%') OR r.review_content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY r.created_date DESC LIMIT #{pageSize} OFFSET #{offset}
